## 方式三：使用 DeepAgent（高级）

`DeepAgent` 允许你完全控制 Agent 的内部执行图结构，支持自定义节点和边。

```go
import (
    "github.com/cloudwego/eino/adk"
    "github.com/cloudwego/eino/components/tool"
    "github.com/cloudwego/eino/compose"
)

// 1. 定义状态类型
type MyState struct {
    Messages   []*schema.Message
    StepCount  int
    CustomData any
}

// 2. 定义状态初始化函数
func initState(ctx context.Context, input *schema.Message) (*MyState, error) {
    return &MyState{
        Messages:  []*schema.Message{input},
        StepCount: 0,
    }, nil
}

// 3. 定义输入转换函数
func inputTransform(ctx context.Context, state *MyState) (*schema.Message, error) {
    return state.Messages[len(state.Messages)-1], nil
}

// 4. 定义输出转换函数
func outputTransform(ctx context.Context, state *MyState) (*schema.Message, error) {
    return state.Messages[len(state.Messages)-1], nil
}

// 5. 创建 DeepAgent
agent, err := adk.NewDeepAgent(ctx, &adk.DeepAgentConfig[MyState]{
    Name:             "DeepAgent",
    InitState:        initState,
    InputTransform:   inputTransform,
    OutputTransform:  outputTransform,
    GraphDescription: "Custom agent with state management",
})
if err != nil {
    panic(err)
}

// 6. 添加节点
agent.AddToolsNode(ctx, &compose.ToolsNodeConfig{
    Tools: []tool.BaseTool{tool1, tool2},
})

// 7. 定义边（执行流程）
agent.AddEdge(compose.START, "tools_node")
agent.AddEdge("tools_node", compose.END)

// 8. 编译并运行
graph, err := agent.Compile()
runner := adk.NewRunner(ctx, adk.RunnerConfig{
    Agent: graph,
})
```

